#include <iostream>
#include <string>

struct Box {
    std::string value;
    auto& get(this auto& self) { return self.value; }
};

int main() {
    Box b{"hello"};
    const Box cb{"world"};
    b.get() = "hi";
    std::cout << b.get() << "\n";
    std::cout << cb.get() << "\n";
}

#include <iostream>
#include <utility>

struct Buffer {
    int data = 42;
    // C++23: one method handles all value categories
    auto&& get(this auto&& self) {
        return std::forward_like<decltype(self)>(self.data);
    }
};

int main() {
    Buffer b;
    const Buffer cb;
    std::cout << b.get() << "\n";        // lvalue
    std::cout << cb.get() << "\n";       // const lvalue
    std::cout << Buffer{}.get() << "\n"; // rvalue
}

#include <iostream>
#include <string>

struct Config {
    std::string host = "localhost";
    int port = 8080;

    auto& set_host(this auto& self, std::string h) {
        self.host = std::move(h);
        return self;
    }
    auto& set_port(this auto& self, int p) {
        self.port = p;
        return self;
    }
    void print() const {
        std::cout << host << ":" << port << "\n";
    }
};

int main() {
    Config c;
    c.set_host("example.com").set_port(443).print();
}

#include <iostream>

int main() {
    auto fib = [](this auto self, int n) -> int {
        if (n <= 1) return n;
        return self(n - 1) + self(n - 2);
    };
    std::cout << fib(10) << "\n";
}

#include <iostream>
#include <string>

struct Printable {
    void print_info(this auto& self) {
        std::cout << "[Info] " << self.describe() << "\n";
    }
};

struct Cat : Printable {
    std::string name;
    explicit Cat(std::string n) : name(std::move(n)) {}
    std::string describe() const { return "Cat: " + name; }
};

struct Dog : Printable {
    std::string name;
    explicit Dog(std::string n) : name(std::move(n)) {}
    std::string describe() const { return "Dog: " + name; }
};

int main() {
    Cat c{"Whiskers"};
    Dog d{"Rex"};
    c.print_info();
    d.print_info();
}

#include <iostream>
#include <variant>
#include <string>

template<typename... Ts>
struct Overloaded : Ts... { using Ts::operator()...; };

int main() {
    using V = std::variant<int, std::string, double>;
    V v1 = 42;
    V v2 = std::string("hello");
    V v3 = 3.14;

    auto visitor = Overloaded{
        [](int x)                { std::cout << "int: " << x << "\n"; },
        [](const std::string& s) { std::cout << "string: " << s << "\n"; },
        [](double d)             { std::cout << "double: " << d << "\n"; },
    };

    std::visit(visitor, v1);
    std::visit(visitor, v2);
    std::visit(visitor, v3);
}

#include <iostream>
#include <string>
struct Email {
    std::string to_, subject_, body_;
    auto to(this auto self, std::string v)      { self.to_ = v; return self; }
    auto subject(this auto self, std::string v) { self.subject_ = v; return self; }
    auto body(this auto self, std::string v)    { self.body_ = v; return self; }
    void send() const {
        std::cout << "To: " << to_ << "\nSubject: " << subject_ << "\n";
    }
};
int main() {
    Email{}.to("alice@example.com").subject("Hello").body("World").send();
}

#include <iostream>
#include <variant>
#include <string>
#include <vector>
struct Counter {
    int ints = 0, strings = 0;
    void operator()(this auto& self, int)                { ++self.ints; }
    void operator()(this auto& self, const std::string&) { ++self.strings; }
    void operator()(this auto& self, double)             { /* ignore */ }
};
int main() {
    using V = std::variant<int, std::string, double>;
    std::vector<V> vs = {1, std::string("hello"), 2.0, 3, std::string("world")};
    Counter c;
    for (auto& v : vs) std::visit(c, v);
    std::cout << "ints: " << c.ints << "\nstrings: " << c.strings << "\n";
}

#include <iostream>
#include <concepts>
#include <string>
template<typename T>
concept HasDescribe = requires(const T& t) {
    { t.describe() } -> std::convertible_to<std::string>;
};
struct Printable {
    void print(this HasDescribe auto const& self) {
        std::cout << self.describe() << "\n";
    }
};
struct GoodClass : Printable {
    std::string describe() const { return "I am GoodClass"; }
};
// struct BadClass : Printable { }; // BadClass{}.print() — compile error
int main() {
    GoodClass g;
    g.print();
}
